class Solution {
    public int minChanges(int n, int k) {
        int count = 0;
        while (n != k) {
            if ((n & 1) == 1 && (k & 1) == 0) {
                n ^= 1;
                count++;
            }
            n >>= 1;
            k >>= 1;
        }
        return count;
    }
}
```
efficiency: HIGH
time complexity: O(log(max(n, k)))
space complexity: O(1)
